import json
import statistics

def calculateStatistics(scores_json):
    try:
        scores = json.loads(scores_json)
    except json.JSONDecodeError:
        return "Invalid JSON format"

    if not isinstance(scores, list):
        return "Invalid JSON format"

    numeric_scores = [float(score) for score in scores if isinstance(score, (int, float))]

    if not numeric_scores:
        return "No numeric scores found"

    mean = statistics.mean(numeric_scores)
    median = statistics.median(numeric_scores)
    mode = statistics.mode(numeric_scores)

    return {
        "Mean": mean,
        "Median": median,
        "Mode": mode
    }
