import java.util.*;

class TrafficNode implements Comparable<TrafficNode> {
    String intersection;
    int trafficDensity;

    public TrafficNode(String intersection, int trafficDensity) {
        this.intersection = intersection;
        this.trafficDensity = trafficDensity;
    }

    @Override
    public int compareTo(TrafficNode other) {
        return Integer.compare(this.trafficDensity, other.trafficDensity);
    }
}

class Graph {
    Map<String, List<Edge>> adjacencyList;

    public Graph() {
        this.adjacencyList = new HashMap<>();
    }

    public void addEdge(String from, String to, int trafficDensity) {
        adjacencyList.computeIfAbsent(from, k -> new ArrayList<>()).add(new Edge(to, trafficDensity));
        adjacencyList.computeIfAbsent(to, k -> new ArrayList<>()).add(new Edge(from, trafficDensity));
    }
}

class Edge {
    String destination;
    int trafficDensity;

    public Edge(String destination, int trafficDensity) {
        this.destination = destination;
        this.trafficDensity = trafficDensity;
    }
}

public class TrafficOptimizer {
    public List<String> trafficOptimizer(Graph graph) {
        PriorityQueue<TrafficNode> pq = new PriorityQueue<>();
        Map<String, Integer> distances = new HashMap<>();
        Map<String, String> previous = new HashMap<>();

        for (String intersection : graph.adjacencyList.keySet()) {
            pq.add(new TrafficNode(intersection, graph.adjacencyList.get(intersection).get(0).trafficDensity));
            distances.put(intersection, Integer.MAX_VALUE);
            previous.put(intersection, null);
        }

        distances.put(pq.peek().intersection, 0);

        while (!pq.isEmpty()) {
            TrafficNode current = pq.poll();

            for (Edge edge : graph.adjacencyList.get(current.intersection)) {
                int distance = distances.get(current.intersection) + edge.trafficDensity;

                if (distance < distances.get(edge.destination)) {
                    distances.put(edge.destination, distance);
                    previous.put(edge.destination, current.intersection);
                    pq.add(new TrafficNode(edge.destination, distance));
                }
            }
        }

        List<String> optimizedPaths = new ArrayList<>();

        for (String intersection : distances.keySet()) {
            if (previous.get(intersection) != null) {
                List<String> path = new ArrayList<>();
                String current = intersection;

                while (current != null) {
                    path.add(0, current);
                    current = previous.get(current);
                }

                optimizedPaths.add(path);
            }
        }

        return optimizedPaths;
    }

    public static void main(String[] args) {
        TrafficOptimizer optimizer = new TrafficOptimizer();

        Graph graph = new Graph();
        graph.addEdge("A", "B", 10);
        graph.addEdge("A", "C", 5);
        graph.addEdge("B", "D", 8);
        graph.addEdge("C", "D", 3);
        graph.addEdge("D", "E", 2);

        List<List<String>> optimizedPaths = optimizer.trafficOptimizer(graph);

        for (List<String> path : optimizedPaths) {
            System.out.println(path);
        }
    }
}
