// Define the ReqStruct
struct ReqStruct {
    int requestID;
    std::string endpoint;
    std::string payload;
};

// Function to log the request
void logRequest(const ReqStruct& req) {
    std::cout << "Request Log: ID - " << req.requestID << ", Endpoint - " << req.endpoint << ", Payload - " << req.payload << std::endl;
}

// Function to validate the endpoint
bool validateEndpoint(const std::string& endpoint) {
    // For simplicity, we'll just check if the endpoint is not empty
    return !endpoint.empty();
}

// Function to generate a response based on the payload
std::string generateResponse(const std::string& payload) {
    // For simplicity, we'll just return a generic response
    return "Response: Payload - " + payload;
}

// Function to process network requests
std::unordered_map<int, std::string> processNetworkRequests(const std::vector<ReqStruct>& requests) {
    std::unordered_map<int, std::string> responses;

    for (const auto& request : requests) {
        logRequest(request);

        if (!validateEndpoint(request.endpoint)) {
            std::cerr << "Invalid endpoint: " << request.endpoint << std::endl;
            continue;
        }

        std::string response = generateResponse(request.payload);

        responses[request.requestID] = response;
    }

    return responses;
}
