        Map<String, Map<String, Object>> statistics = new HashMap<>();

        for (Map.Entry<String, Map<String, Object>> entry : userInteractions.entrySet()) {
            String action = entry.getKey();
            Map<String, Object> metadata = entry.getValue();

            if (!statistics.containsKey(action)) {
                statistics.put(action, new HashMap<>());
            }

            statistics.get(action).put("clicks", ((Long) statistics.get(action).get("clicks")).longValue() + 1);
            statistics.get(action).put("views", ((Long) statistics.get(action).get("views")).longValue() + 1);
            statistics.get(action).put("time_spent", ((Long) statistics.get(action).get("time_spent")).longValue() + (Long) metadata.getOrDefault("time_spent", 0L));
        }

        return statistics;
    }

    public static void main(String[] args) {
        Map<String, Map<String, Object>> userInteractions = new HashMap<>();
        Map<String, Object> interaction1 = new HashMap<>();
        interaction1.put("time_spent", 10L);
        userInteractions.put("click", interaction1);

