import java.util.*;

public class NetworkAnalyzer {
    public static Set<String> analyzeNetworkConnectivity(Map<String, List<String>> graph) {
        Set<String> criticalNodes = new HashSet<>();

        for (String node : graph.keySet()) {
            if (isBridgeNode(graph, node)) {
                criticalNodes.add(node);
            }
        }

        return criticalNodes;
    }

    private static boolean isBridgeNode(Map<String, List<String>> graph, String node) {
        int degree = graph.get(node).size();

        for (String neighbor : graph.get(node)) {
            if (graph.get(neighbor).size() >= degree) {
                return false;
            }
        }

        return true;
    }

    public static void main(String[] args) {
        Map<String, List<String>> graph = new HashMap<>();
        graph.put("A", Arrays.asList("B", "C"));
        graph.put("B", Arrays.asList("A", "D", "E"));
        graph.put("C", Arrays.asList("A", "F"));
        graph.put("D", Arrays.asList("B"));
        graph.put("E", Arrays.asList("B", "F"));
        graph.put("F", Arrays.asList("C", "E"));

        Set<String> criticalNodes = analyzeNetworkConnectivity(graph);
        System.out.println("Critical Nodes: " + criticalNodes);
    }
}
