std::map<std::string, std::string> settings = {
    {"theme", "light"},
    {"language", "English"},
    {"font_size", "12"}
};

void processCommandLine(const std::string& command) {
    std::istringstream iss(command);
    std::string action, setting, value;

    if (!(iss >> action >> setting >> value)) {
        std::cout << "Invalid command format. Please use 'set <setting> <value>', 'display <setting>', or 'reset <setting>'." << std::endl;
        return;
    }

    if (action == "set") {
        settings[setting] = value;
        std::cout << "Setting '" << setting << "' to '" << value << "'" << std::endl;
    } else if (action == "display") {
        std::cout << "Setting: " << setting << " = " << settings[setting] << std::endl;
    } else if (action == "reset") {
        if (settings.find(setting) != settings.end()) {
            settings.erase(setting);
            std::cout << "Resetting '" << setting << "'" << std::endl;
        } else {
            std::cout << "'" << setting << "' setting not found." << std::endl;
        }
    }
}

int main() {
    processCommandLine("set theme dark");
    processCommandLine("display theme");
    processCommandLine("reset language");
    processCommandLine("invalid_command setting language");
    return 0;
}
