struct AirportGates {
    gates: Mutex<HashMap<String, String>>,
}

impl AirportGates {
    fn new() -> AirportGates {
        AirportGates {
            gates: Mutex::new(HashMap::new()),
        }
    }

    fn manageAirportGates(&self, gate_action: GateAction) {
        let mut gates = self.gates.lock().unwrap();
        match gate_action.action.as_str() {
            "allocate" => {
                gates.insert(gate_action.gate_id.clone(), "allocated".to_string());
                println!("Gate {} allocated successfully.", gate_action.gate_id);
            }
            "deallocate" => {
                if gates.contains_key(&gate_action.gate_id) {
                    gates.remove(&gate_action.gate_id);
                    println!("Gate {} deallocated successfully.", gate_action.gate_id);
                } else {
                    println!("Gate {} not allocated.", gate_action.gate_id);
                }
            }
            "status" => {
                if gates.contains_key(&gate_action.gate_id) {
                    println!("Gate {} is {}.", gate_action.gate_id, gates.get(&gate_action.gate_id).unwrap());
                } else {
                    println!("Gate {} not allocated.", gate_action.gate_id);
                }
            }
            _ => println!("Invalid action. Please use 'allocate', 'deallocate', or 'status'."),
        }
    }
}

fn main() {
    let mut airport_gates = AirportGates::new();
    let gate_action1 = GateAction::new("gate1".to_string(), "allocate".to_string());
    let gate_action2 = GateAction::new("gate2".to_string(), "allocate".to_string());
    let gate_action3 = GateAction::new("gate1".to_string(), "status".to_string());
