fn calculate_battery_life(current_percentage: f64, activities: Vec<f64>) -> f64 {
    let initial_battery_life = current_percentage;
    let mut total_usage = 0.0;

    for activity in activities {
        total_usage += activity;
    }

    let remaining_percentage = initial_battery_life - total_usage;

    // Ensure the remaining percentage is within the valid range
    remaining_percentage.max(0.0).min(100.0)
}

fn main() {
    let current_percentage = 50.0;
    let activities = vec![10.0, 20.0, 30.0];
    let remaining_percentage = calculate_battery_life(current_percentage, activities);
    println!("Estimated remaining battery percentage: {}", remaining_percentage);
}
