using namespace std;

class AirportGateManager {
private:
    map<int, string> gates;
    map<string, int> flights;

public:
    map<string, int> manageAirportGates(map<string, string> actions) {
        if (actions["action"] == "assign") {
            int flightNumber = stoi(actions["flight_number"]);
            int gateNumber = stoi(actions["gate_number"]);
            if (gates.find(gateNumber) == gates.end()) {
                gates[gateNumber] = to_string(flightNumber);
            } else {
                if (gates[gateNumber] != to_string(flightNumber)) {
                    return flights;
                }
                gates[gateNumber] = to_string(flightNumber);
            }
        } else if (actions["action"] == "unassign") {
            int gateNumber = stoi(actions["gate_number"]);
            if (gates.find(gateNumber) != gates.end()) {
                string flightNumber = gates[gateNumber];
                gates.erase(gateNumber);
                flights[flightNumber] = 0;
            }
        } else if (actions["action"] == "query") {
            int gateNumber = stoi(actions["gate_number"]);
            if (gates.find(gateNumber) != gates.end()) {
                return { { "gate", to_string(gateNumber) }, { "flight", gates[gateNumber] } };
            } else {
                return { { "gate", to_string(gateNumber) }, { "flight", "None" } };
            }
        }

        return flights;
    }
};

int main() {
    AirportGateManager manager;
    map<string, string> actions = { { "action", "assign" }, { "flight_number", "1234" }, { "gate_number", "1" } };
    map<string, int> result = manager.manageAirportGates(actions);

    actions = { { "action", "assign" }, { "flight_number", "5678" }, { "gate_number", "2" } };
    result = manager.manageAirportGates(actions);

    actions = { { "action", "query" }, { "gate_number", "1" } };
    result = manager.manageAirportGates(actions);

