import java.util.*;

public class LoginHistory {
    private Map<String, List<LoginRecord>> loginHistory;

    public LoginHistory() {
        this.loginHistory = new HashMap<>();
    }

    public void processLoginHistory(JSONObject operation, String userId, Long timestamp) {
        if (operation.getString("type").equals("add")) {
            addLoginRecord(operation, userId, timestamp);
        } else if (operation.getString("type").equals("retrieve")) {
            retrieveRecentLoginActivities(operation, userId);
        } else if (operation.getString("type").equals("delete")) {
            deleteLoginData(operation, userId);
        }
    }

    private void addLoginRecord(JSONObject operation, String userId, Long timestamp) {
        if (!loginHistory.containsKey(userId)) {
            loginHistory.put(userId, new ArrayList<>());
        }
        loginHistory.get(userId).add(new LoginRecord(timestamp));
    }

    private void retrieveRecentLoginActivities(JSONObject operation, String userId) {
        if (loginHistory.containsKey(userId)) {
            List<LoginRecord> recentActivities = loginHistory.get(userId);
            Collections.reverse(recentActivities);
            System.out.println("Recent login activities for user " + userId + ":");
            for (LoginRecord record : recentActivities) {
                System.out.println(record.getTimestamp() + " - " + record.getUserID());
            }
        } else {
            System.out.println("User ID not found.");
        }
    }

    private void deleteLoginData(JSONObject operation, String userId) {
        if (loginHistory.containsKey(userId)) {
            loginHistory.get(userId).clear();
        } else {
            System.out.println("User ID not found.");
        }
    }

    public static class LoginRecord {
        private Long timestamp;
        private String userID;

        public LoginRecord(Long timestamp, String userID) {
            this.timestamp = timestamp;
            this.userID = userID;
        }

        public Long getTimestamp() {
            return timestamp;
        }

        public String getUserID() {
            return userID;
        }
    }
}
