def manageStudentRecords(student_data):
    operations = {
        "add": lambda data: student_data.append(data),
        "update": lambda data, index: student_data[index] = data,
        "remove": lambda index: del student_data[index],
        "fetch": lambda index: student_data[index]
    }

    for operation in student_data:
        operation_type = operation["operation"]
        student_id = operation["student_id"]
        student_details = operation["student_details"]

        if operation_type == "add":
            operations["add"](student_details)
        elif operation_type == "update":
            if student_id in [student["student_id"] for student in student_data]:
                index = student_data.index(next(student for student in student_data if student["student_id"] == student_id))
                operations["update"](student_details, index)
