public class ReminderSystem {
    private Map<String, Map<String, Object>> reminders;

    public ReminderSystem() {
        this.reminders = new HashMap<>();
    }

    public void configureReminderSystem(JSONObject eventDetails) {
        String eventType = eventDetails.getString("event_type");
        String date = eventDetails.getString("date");
        String time = eventDetails.getString("time");
        String importance = eventDetails.getString("importance");

        Map<String, Object> reminder = new HashMap<>();
        reminder.put("date", date);
        reminder.put("time", time);
        reminder.put("importance", importance);

        reminders.put(eventType, reminder);

        // Setting updates
        if (eventDetails.has("reminder_time")) {
            reminder.put("time", eventDetails.getString("reminder_time"));
        }

        if (eventDetails.has("delete")) {
            if (eventDetails.getBoolean("delete")) {
                reminders.remove(eventType);
            }
        }
    }

    public String getReminderDetails(String eventType) {
        if (reminders.containsKey(eventType)) {
            Map<String, Object> reminder = reminders.get(eventType);
            return "Event Type: " + eventType + ", Date: " + reminder.get("date") + ", Time: " + reminder.get("time") + ", Importance: " + reminder.get("importance");
        } else {
            return "No reminders found for this event type";
        }
    }

    public static void main(String[] args) {
        ReminderSystem reminderSystem = new ReminderSystem();

        JSONObject event1 = new JSONObject();
        event1.put("event_type", "Meeting");
        event1.put("date", "2024-03-20");
        event1.put("time", "10:00 AM");
        event1.put("importance", "High");

        JSONObject event2 = new JSONObject();
        event2.put("event_type", "Appointment");
        event2.put("date", "2024-03-22");
        event2.put("time", "2:00 PM");
        event2.put("importance", "Low");

        reminderSystem.configureReminderSystem(event1);
        reminderSystem.configureReminderSystem(event2);

        System.out.println(reminderSystem.getReminderDetails("Meeting"));
        System.out.println(reminderSystem.getReminderDetails("Appointment"));
    }
}
