PermissionNode* createPermissionNode(const std::string& permission) {
    PermissionNode* node = new PermissionNode();
    node->permission = permission;
    return node;
}

// Define a function to add a child node to the permission tree
void addChild(PermissionNode* parent, const std::string& child) {
    if (parent->children.find(child) != parent->children.end()) {
        std::cout << "Child already exists in the tree." << std::endl;
        return;
    }

    PermissionNode* childNode = createPermissionNode(child);
    parent->children[child] = childNode;
}

// Define a function to update a permission in the tree
void updatePermission(PermissionNode* parent, const std::string& permission, const std::string& newPermission) {
    if (parent->children.find(permission) == parent->children.end()) {
        std::cout << "Permission does not exist in the tree." << std::endl;
        return;
    }

    PermissionNode* node = parent->children[permission];
    node->permission = newPermission;
}

// Define a function to remove a permission from the tree
void removePermission(PermissionNode* parent, const std::string& permission) {
    if (parent->children.find(permission) == parent->children.end()) {
        std::cout << "Permission does not exist in the tree." << std::endl;
        return;
    }

    delete parent->children[permission];
    parent->children.erase(permission);
}

// Define the managePermissions function
void managePermissions(PermissionNode* root, const std::map<std::string, std::map<std::string, std::string>>& operations) {
    for (const auto& operation : operations) {
        if (operation.second.find("operation") == operation.second.end()) {
            std::cout << "Invalid operation." << std::endl;
            continue;
        }

        std::string operationType = operation.second.at("operation");
        std::string permission = operation.second.at("permission");
        std::string parentPermission = operation.second.at("parent");

        if (operationType == "add") {
            addChild(root, permission);
        } else if (operationType == "update") {
            updatePermission(root, permission, operation.second.at("newPermission"));
        } else if (operationType == "remove") {
            removePermission(root, permission);
        }
    }
}

// Define a function to print the permission tree
void printPermissionTree(PermissionNode* root, int indent = 0) {
    for (int i = 0; i < indent; ++i) {
        std::cout << "  ";
    }
    std::cout << root->permission << std::endl;

    for (const auto& child : root->children) {
        printPermissionTree(child.second, indent + 1);
    }
}

int main() {
    // Create the root node
    PermissionNode* root = createPermissionNode("root");

    // Create some example operations
    std::map<std::string, std::map<std::string, std::string>> operations = {
        {{"operation", "add"}, {"permission", "admin"}, {"parent", "root"}},
        {{"operation", "add"}, {"permission", "moderator"}, {"parent", "admin"}},
        {{"operation", "add"}, {"permission", "user"}, {"parent", "moderator"}},
        {{"operation", "update"}, {"permission", "admin"}, {"newPermission", "superadmin"}},
        {{"operation", "remove"}, {"permission", "user"}}
    };

    // Manage the permissions
    managePermissions(root, operations);

    // Print the permission tree
    printPermissionTree(root);

    return 0;
}
