fn process_grid_operations(matrix: Vec<Vec<i32>>, operations: Vec<String>) -> Vec<Vec<i32>> {
    let mut result = matrix.clone();

    for operation in operations {
        match operation.as_str() {
            "rotate" => result = rotate_90_clockwise(&mut result),
            "flip" => result = flip_horizontally(&mut result),
            "invert" => result = invert(&mut result),
            _ => panic!("Invalid operation"),
        }
    }

    result
}

fn rotate_90_clockwise(matrix: &mut Vec<Vec<i32>>) -> Vec<Vec<i32>> {
    let n = matrix.len();
    let m = matrix[0].len();

    for i in 0..n / 2 {
        for j in 0..m / 2 {
            let temp = matrix[i][j];
            matrix[i][j] = matrix[n - 1 - i][m - 1 - j];
            matrix[n - 1 - i][m - 1 - j] = temp;
        }
    }

    for i in 0..n / 2 {
        for j in m / 2..m {
            let temp = matrix[i][j];
            matrix[i][j] = matrix[n - 1 - i][j];
            matrix[n - 1 - i][j] = temp;
        }
    }

    for i in (n / 2)..n {
        for j in 0..m / 2 {
            let temp = matrix[i][j];
            matrix[i][j] = matrix[i][m - 1 - j];
            matrix[i][m - 1 - j] = temp;
        }
    }

    for i in (n / 2)..n {
        for j in m / 2..m {
            let temp = matrix[i][j];
            matrix[i][j] = matrix[i][j];
            matrix[i][j] = temp;
        }
    }

    matrix
}

fn flip_horizontally(matrix: &mut Vec<Vec<i32>>) -> Vec<Vec<i32>> {
    for i in 0..matrix.len() {
        for j in 0..matrix[0].len() / 2 {
            let temp = matrix[i][j];
            matrix[i][j] = matrix[i][matrix[0].len() - 1 - j];
            matrix[i][matrix[0].len() - 1 - j] = temp;
        }
    }

    matrix
}

fn invert(matrix: &mut Vec<Vec<i32>>) -> Vec<Vec<i32>> {
    for i in 0..matrix.len() {
        for j in 0..matrix[0].len() {
            if matrix[i][j] == 0 {
                matrix[i][j] = 1;
            } else {
                matrix[i][j] = 0;
            }
        }
    }

    matrix
}

fn main() {
    let matrix = vec![
        vec![1, 0, 0],
        vec![0, 1, 0],
        vec![0, 0, 1],
    ];

    let operations = vec![
        "rotate".to_string(),
        "flip".to_string(),
        "invert".to_string(),
    ];

    let result = process_grid_operations(matrix, operations);
    for row in result {
        for num in row {
            print!("{} ", num);
        }
        println!();
    }
}
