        String cardNumber = paymentDetails.getString("card_number");
        if (!isValidLuhnCardNumber(cardNumber)) {
            return "{\"transaction_status\": \"failed\", \"message\": \"Invalid card number\"}";
        }

        // Check if the required fields are present
        if (!paymentDetails.has("card_type") || !paymentDetails.has("amount")) {
            return "{\"transaction_status\": \"failed\", \"message\": \"Missing required fields\"}";
        }

        // Process the payment
        try {
            // Simulate a payment process
            if (Double.parseDouble(paymentDetails.getString("amount")) > 1000) {
                return "{\"transaction_status\": \"success\", \"message\": \"Payment processed successfully\"}";
            } else {
                return "{\"transaction_status\": \"failed\", \"message\": \"Insufficient amount\"}";
            }
        } catch (NumberFormatException e) {
            return "{\"transaction_status\": \"failed\", \"message\": \"Invalid amount\"}";
        }
