use std::collections::HashMap;

enum NodeType {
    Device,
    Subnet,
}

enum Action {
    Add,
    Update,
    Remove,
}

struct TreeNode {
    value: String,
    children: HashMap<String, TreeNode>,
    node_type: NodeType,
}

fn manage_network_config(action: Action, node_value: String, node_type: NodeType, children: HashMap<String, TreeNode>) -> TreeNode {
    match action {
        Action::Add => TreeNode {
            value: node_value,
            children,
            node_type,
        },
        Action::Update => {
            let mut updated_children = HashMap::new();
            for (child_value, child) in children {
                if child.value != node_value {
                    updated_children.insert(child_value.clone(), manage_network_config(Action::Update, child_value.clone(), child.node_type, child.children));
                } else {
                    updated_children.insert(child_value.clone(), child);
                }
            }
            TreeNode {
                value: node_value,
                children: updated_children,
                node_type,
            }
        }
        Action::Remove => {
            let mut updated_children = HashMap::new();
            for (child_value, child) in children {
                if child.value != node_value {
                    updated_children.insert(child_value.clone(), manage_network_config(Action::Remove, child_value.clone(), child.node_type, child.children));
                }
            }
            TreeNode {
                value: String::new(),
                children: updated_children,
                node_type,
            }
        }
    }
}

fn get_config(node_value: String, node_type: NodeType, tree: TreeNode) -> String {
    match node_type {
        NodeType::Device => format!("Device: {}", tree.value),
        NodeType::Subnet => format!("Subnet: {}", tree.value),
    }
}

fn main() {
    let mut root = manage_network_config(Action::Add, "R1".to_string(), NodeType::Device, HashMap::new());
    root = manage_network_config(Action::Add, "R2".to_string(), NodeType::Device, HashMap::new());
    root = manage_network_config(Action::Add, "192.168.1.0/24".to_string(), NodeType::Subnet, HashMap::new());

    println!("{}", get_config("R1".to_string(), NodeType::Device, root.clone()));
    println!("{}", get_config("R2".to_string(), NodeType::Device, root.clone()));
    println!("{}", get_config("192.168.1.0/24".to_string(), NodeType::Subnet, root.clone()));

    root = manage_network_config(Action::Update, "R1".to_string(), NodeType::Device, HashMap::new());
    root = manage_network_config(Action::Remove, "R2".to_string(), NodeType::Device, HashMap::new());

    println!("{}", get_config("R1".to_string(), NodeType::Device, root.clone()));
    println!("{}", get_config("192.168.1.0/24".to_string(), NodeType::Subnet, root.clone()));
}
