    public static Map<String, Object> graphTraversalManager(JSONObject graphData) {
        String traversalAlgorithm = graphData.getString("algorithm");
        String startNode = graphData.getString("startNode");
        String graphType = graphData.getString("graphType");

        Map<String, Object> result = new HashMap<>();
        result.put("traversalAlgorithm", traversalAlgorithm);
        result.put("startNode", startNode);
        result.put("graphType", graphType);

        if (traversalAlgorithm.equals("BFS")) {
            if (graphType.equals("directed")) {
                result.put("result", bfsDirected(graphData));
            } else if (graphType.equals("undirected")) {
                result.put("result", bfsUndirected(graphData));
            } else {
                result.put("error", "Invalid graph type for BFS");
            }
        } else if (traversalAlgorithm.equals("DFS")) {
            if (graphType.equals("directed")) {
                result.put("result", dfsDirected(graphData));
            } else if (graphType.equals("undirected")) {
                result.put("result", dfsUndirected(graphData));
            } else {
                result.put("error", "Invalid graph type for DFS");
            }
        } else {
            result.put("error", "Invalid traversal algorithm");
        }

        return result;
    }

    public static List<String> bfsDirected(JSONObject graphData) {
        Map<String, List<String>> graph = new HashMap<>();
        for (String node : graphData.keySet()) {
            graph.put(node, graphData.get(node).toString().split(","));
        }

        Set<String> visited = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.add(graphData.getString("startNode"));
        visited.add(graphData.getString("startNode"));

        List<String> result = new ArrayList<>();
        while (!queue.isEmpty()) {
            String node = queue.poll();
            result.add(node);

            for (String neighbor : graph.get(node)) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
            }
        }

        return result;
    }

