    let image = match format_str.as_str() {
        "jpg" | "jpeg" => ImageBuffer::from_raw(32, 32, image_bytes),
        "png" => Reader::new(Cursor::new(image_bytes)).into_image().unwrap(),
        _ => panic!("Unsupported format"),
    };

