        .iter()
        .flat_map(|(x, y, c)| vec![c; 1])
        .collect::<Vec<_>>();

    let grayscale_image = RgbaImage::from_raw(32, 32, grayscale_image).unwrap();

    let grayscale_bytes = grayscale_image.to_vec();

    let writer = Writer::new(Vec::new(), image.width(), image.height(), ImageFormat::Jpeg).unwrap();

    writer.write_image(&grayscale_image).unwrap();

    writer.into_inner().unwrap()
}
