        TaskManager {
            tasks: HashMap::new(),
        }
    }

    fn manage_task_priority(&mut self, request: Value) -> Result<(), String> {
        let task_id = request["task_id"].as_str().unwrap().to_string();
        let new_priority = request["new_priority"].as_u64().unwrap();

        if let Some(priority) = self.tasks.get(&task_id) {
            if *priority > new_priority {
                return Err("Cannot decrease priority".to_string());
            }
        }

        self.tasks.insert(task_id, new_priority);

        Ok(())
    }
}

