import java.util.*;

public class FileSystemSimulator {
    private Map<String, Object> root;
    private String currentPath;

    public FileSystemSimulator() {
        this.root = new HashMap<>();
        this.currentPath = "";
    }

    public void fs_simulator(Map<String, Object> actions) {
        for (Map.Entry<String, Object> action : actions.entrySet()) {
            if (action.getKey().equals("add")) {
                addFolder(action.getValue());
            } else if (action.getKey().equals("move")) {
                moveFolder(action.getValue());
            } else if (action.getKey().equals("remove")) {
                removeFolder(action.getValue());
            } else if (action.getKey().equals("fetch path")) {
                fetchPath(action.getValue());
            }
        }
    }

    private void addFolder(Map<String, Object> action) {
        if (!action.containsKey("name") || !action.containsKey("parent")) {
            throw new RuntimeException("Invalid action format");
        }
        String parent = (String) action.get("parent");
        String name = (String) action.get("name");
        if (!root.containsKey(parent)) {
            root.put(parent, new HashMap<>());
        }
        Map<String, Object> folder = root.get(parent);
        folder.put(name, new HashMap<>());
        currentPath += (parent.equals("") ? "" : parent + "/");
        currentPath += name + "/";
    }

    private void moveFolder(Map<String, Object> action) {
        if (!action.containsKey("name") || !action.containsKey("to") || !action.containsKey("from")) {
            throw new RuntimeException("Invalid action format");
        }
        String from = (String) action.get("from");
        String to = (String) action.get("to");
        if (!root.containsKey(from)) {
            throw new RuntimeException("Folder not found");
        }
        Map<String, Object> folder = root.get(from);
        if (!folder.containsKey("name")) {
            throw new RuntimeException("Folder not found");
        }
        String name = (String) folder.get("name");
        folder.remove(name);
        root.get(to).put(name, folder);
        currentPath = currentPath.substring(0, currentPath.lastIndexOf('/'));
    }

    private void removeFolder(Map<String, Object> action) {
        if (!action.containsKey("name") || !action.containsKey("parent")) {
            throw new RuntimeException("Invalid action format");
        }
        String parent = (String) action.get("parent");
        String name = (String) action.get("name");
        if (!root.containsKey(parent)) {
            throw new RuntimeException("Folder not found");
        }
        Map<String, Object> folder = root.get(parent);
        if (!folder.containsKey("name")) {
            throw new RuntimeException("Folder not found");
        }
        String folderName = (String) folder.get("name");
        folder.remove(folderName);
        if (folder.isEmpty()) {
            root.remove(parent);
        }
        currentPath = currentPath.substring(0, currentPath.lastIndexOf('/'));
    }

    private void fetchPath(Map<String, Object> action) {
        if (!action.containsKey("name")) {
            throw new RuntimeException("Invalid action format");
        }
        String name = (String) action.get("name");
        if (name.equals("")) {
            System.out.println(currentPath);
        } else {
            Map<String, Object> folder = root.get(currentPath);
            String path = currentPath;
