    std::map<std::string, Contact> phonebook;

    for (const auto& command : commands) {
        const std::string& commandType = command.first;
        const std::map<std::string, std::string>& commandDetails = command.second;

        if (commandType == "add") {
            Contact newContact;
            newContact.name = commandDetails.at("name");
            newContact.number = commandDetails.at("number");
            phonebook[newContact.name] = newContact;
        } else if (commandType == "delete") {
            phonebook.erase(commandDetails.at("name"));
        } else if (commandType == "update") {
            if (phonebook.find(commandDetails.at("name")) != phonebook.end()) {
                phonebook[commandDetails.at("name)].name = commandDetails.at("name");
                phonebook[commandDetails.at("name)].number = commandDetails.at("number");
            }
        } else if (commandType == "search") {
            for (const auto& contact : phonebook) {
                if (contact.second.name == commandDetails.at("name")) {
                    std::cout << "Name: " << contact.second.name << ", Number: " << contact.second.number << std::endl;
                    return phonebook;
                }
            }
        }
    }

    return phonebook;
}

