class ConfigTree:
    def __init__(self, params):
        self.params = params
        self.children = {}

    def add_child(self, key, value):
        if key in self.params:
            self.children[key] = ConfigTree({k: v for k, v in self.params.items() if k != key})
            if isinstance(value, dict):
                for k, v in value.items():
                    self.children[key].add_child(k, v)
            else:
                self.children[key] = value
        else:
            raise KeyError(f"No configuration found for key '{key}'")

    def modify_config(self, key, value):
        if key in self.children:
            if isinstance(value, dict):
                for k, v in value.items():
                    self.children[key].modify_config(k, v)
            else:
                self.children[key] = value
        else:
            raise KeyError(f"No configuration found for key '{key}'")

    def retrieve_config(self, key):
        if key in self.children:
            if isinstance(self.children[key], dict):
                return self.children[key]
            else:
                return self.children[key]
        else:
            raise KeyError(f"No configuration found for key '{key}'")


def generate_config_tree(params):
    config_tree = ConfigTree(params)
    return config_tree


# Example usage
params = {
    "hostname": "example_device",
    "ip_addresses": {
        "ip_address1": "192.168.1.1",
        "ip_address2": "192.168.1.2"
    },
    "routing_protocols": {
        "protocol1": " OSPF",
        "protocol2": "EIGRP"
    }
}

config_tree = generate_config_tree(params)

print(config_tree.retrieve_config("hostname").value)
