                addEmployee(employeeId);
                break;
            case "delete":
                deleteEmployee(employeeId);
                break;
            case "search":
                searchEmployee(employeeId);
                break;
            default:
                System.out.println("Invalid operation type");
                return;
        }
    }

    private void addEmployee(String employeeId) {
        if (employeeSet.contains(employeeId)) {
            System.out.println("Employee ID already exists");
            return;
        }
        employeeSet.add(employeeId);
        System.out.println("Employee ID added successfully");
    }

    private void deleteEmployee(String employeeId) {
        if (!employeeSet.contains(employeeId)) {
            System.out.println("Employee ID not found");
            return;
        }
        employeeSet.remove(employeeId);
        System.out.println("Employee ID deleted successfully");
    }

    private void searchEmployee(String employeeId) {
        if (employeeSet.contains(employeeId)) {
            System.out.println("Employee ID found");
        } else {
            System.out.println("Employee ID not found");
        }
    }

