#include <iostream>
#include <queue>
#include <vector>
#include <limits>
#include <unordered_map>

using namespace std;

vector<int> findShortestPath(unordered_map<int, vector<int>> graph, int start, int end) {
    unordered_map<int, int> distances;
    unordered_map<int, int> previous;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> priorityQueue;

    for (auto& node : graph) {
        distances[node.first] = numeric_limits<int>::max();
        previous[node.first] = -1;
    }

    distances[start] = 0;
    priorityQueue.push({0, start});

    while (!priorityQueue.empty()) {
        int currentNode = priorityQueue.top().second;
        priorityQueue.pop();

        if (currentNode == end) {
            vector<int> path;
            while (currentNode != -1) {
                path.push_back(currentNode);
                currentNode = previous[currentNode];
            }
            reverse(path.begin(), path.end());
            return path;
        }

        for (int neighbor : graph[currentNode]) {
            int distance = distances[currentNode] + 1;
            if (distance < distances[neighbor]) {
                distances[neighbor] = distance;
                previous[neighbor] = currentNode;
                priorityQueue.push({distance, neighbor});
            }
        }
    }

    return {};
}

int main() {
    unordered_map<int, vector<int>> graph = {
        {0, {1, 2}},
        {1, {0, 3}},
        {2, {0, 4}},
        {3, {1}},
        {4, {2}}
    };

    vector<int> path = findShortestPath(graph, 0, 4);
    for (int node : path) {
        cout << node << " ";
    }
    cout << endl;

    return 0;
}
