// Define a Tree class to represent the hierarchical structure
class Node {
    String value;
    Node[] children;

    public Node(String value) {
        this.value = value;
        this.children = new Node[0];
    }

    public void addChild(Node node) {
        Node[] newChildren = new Node[children.length + 1];
        System.arraycopy(children, 0, newChildren, 0, children.length);
        newChildren[children.length] = node;
        children = newChildren;
    }
}

// Define the configureApplicationSettings method
public class Main {
    public static void configureApplicationSettings(Node root, Map<String, Object> settings) {
        if (root == null) {
            return;
        }

        if (settings.containsKey(root.value)) {
            root.value = (String) settings.get(root.value);
        }

        for (Node child : root.children) {
            configureApplicationSettings(child, settings);
        }
    }

    public static void main(String[] args) {
        // Create a sample tree
        Node root = new Node("Settings");
        root.addChild(new Node("Display"));
        root.addChild(new Node("Sound"));
        root.getChildren()[0].addChild(new Node("Resolution"));
        root.getChildren()[0].addChild(new Node("Brightness"));

        // Define the configuration settings
        Map<String, Object> settings = new HashMap<>();
        settings.put("Display", "High");
        settings.put("Sound", "Max");

        // Apply the configuration settings
        configureApplicationSettings(root, settings);

        // Print the updated tree
        System.out.println(root.value);  // Output: High
        System.out.println(root.getChildren()[0].value);  // Output: Max
        System.out.println(root.getChildren()[0].getChildren()[0].value);  // Output: High
        System.out.println(root.getChildren()[0].getChildren()[1].value);  // Output: Max
    }
}
