public class MatrixTransformer {
    public static int[][] transformMatrix(int[][] matrix, String operation) {
        if (operation.equals("rotate_left")) {
            return rotateLeft(matrix);
        } else if (operation.equals("rotate_right")) {
            return rotateRight(matrix);
        } else if (operation.equals("flip_vertical")) {
            return flipVertical(matrix);
        } else if (operation.equals("flip_horizontal")) {
            return flipHorizontal(matrix);
        } else {
            throw new UnsupportedOperationException("Unsupported operation mode");
        }
    }

    private static int[][] rotateLeft(int[][] matrix) {
        return transpose(matrix);
    }

    private static int[][] rotateRight(int[][] matrix) {
        return transpose(transpose(matrix));
    }

    private static int[][] flipVertical(int[][] matrix) {
        return reverseArray(matrix[0]);
    }

    private static int[][] flipHorizontal(int[][] matrix) {
        return reverseArray(matrix);
    }

    private static int[][] transpose(int[][] matrix) {
        int[][] result = new int[matrix[0].length][matrix.length];
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[0].length; j++) {
                result[j][i] = matrix[i][j];
            }
        }
        return result;
    }

    private static int[] reverseArray(int[] array) {
        int[] result = new int[array.length];
        for (int i = 0; i < array.length; i++) {
            result[i] = array[array.length - 1 - i];
        }
        return result;
    }

    public static void main(String[] args) {
        int[][] matrix = {
            {1, 2, 3},
            {4, 5, 6},
            {7, 8, 9}
        };

        int[][] transformedMatrix = transformMatrix(matrix, "rotate_left");

        for (int[] row : transformedMatrix) {
            for (int element : row) {
                System.out.print(element + " ");
            }
            System.out.println();
        }
    }
}
